#include<bits/stdc++.h>
using namespace std;
int main() {
	int n, a[2][600], maxz = 0;

	long long c = 0;

	bool b[600] = {0};

	cin >> n;

	for (int i = 0; i < n; i++) {

		cin >> a[0][i];

	}

	for (int i = 0; i < n; i++) {

		cin >> a[1][i];

	}

	for (int j = 0; j < n; j++) {

		for (int i = 0; i < n; i++) {

			maxz = max(maxz, a[1][i]);

		}

		for (int i = 0; i < n; i++)

			if (a[1][i] == maxz) {

				a[1][i] = 0;

				for (int k = a[0][i] - 1; k >= 0; k--) {

					if (b[k] == 0) {

						b[k] = 1;

						c += maxz;

						break;

					}

				}

			}

		maxz = 0;

	}

	cout << c;

	return 0;

}
